import React from 'react';

function App() {
  return (
    <div style={styles.container}>
      <header style={styles.header}>
        <h1>Dora's Clothing Store 👗</h1>
        <p>Style that speaks for you!</p>
      </header>

      <section style={styles.section}>
        <h2>🔥 Featured Products</h2>
        <div style={styles.products}>
          <div style={styles.card}>
            <img
              src="https://via.placeholder.com/150"
              alt="T-Shirt"
              style={styles.image}
            />
            <h3>Cool T-Shirt</h3>
            <p>Rs.499</p>
          </div>
          <div style={styles.card}>
            <img
              src="https://via.placeholder.com/150"
              alt="Hoodie"
              style={styles.image}
            />
            <h3>Winter Hoodie</h3>
            <p>Rs.999</p>
          </div>
        </div>
      </section>

      <footer style={styles.footer}>
        <p>&copy; 2025 Dora's Clothing Store. All rights reserved.</p>
      </footer>
    </div>
  );
}

const styles = {
  container: {
    fontFamily: 'sans-serif',
    padding: '20px',
    textAlign: 'center',
    backgroundColor: '#fefefe',
  },
  header: {
    backgroundColor: '#f8d7da',
    padding: '30px',
    borderRadius: '12px',
    marginBottom: '20px',
  },
  section: {
    marginTop: '20px',
  },
  products: {
    display: 'flex',
    justifyContent: 'center',
    gap: '30px',
    marginTop: '15px',
    flexWrap: 'wrap',
  },
  card: {
    border: '1px solid #ddd',
    borderRadius: '10px',
    padding: '15px',
    width: '200px',
    boxShadow: '0 4px 8px rgba(0,0,0,0.1)',
  },
  image: {
    width: '100%',
    borderRadius: '8px',
  },
  footer: {
    marginTop: '40px',
    padding: '10px',
    backgroundColor: '#f1f1f1',
    borderRadius: '8px',
  },
};

export default App;
